templates.templateContent:
{% include "EVPN-DMZ/DEFN-VRF" %}
{% include "EVPN-DMZ/DEFN-ROLES" %}
{% include "EVPN-DMZ/DEFN-LOOPBACKS" %}
{% include "EVPN-DMZ/DEFN-OVERLAY" %}

{# Resolve the VRF objects upfront #}
{% set vrf_objs = [] %}
{% for input_vrf in vrf_list %}
  {% set _vrf = (DEFN_VRF | selectattr("name", "equalto", input_vrf) | list | first) %}
  {% if _vrf %}{% do vrf_objs.append(_vrf | first) %}{% endif %}
{% endfor %}

{# UNDERLAY LOOPBACKS #}
interface {{DEFN_LOOP_NAME['UNDERLAY']}}
description UNDERLAY-NVE-INTERFACE
ip address {{DEFN_LOOP_UNDERLAY[__device.hostname]}} 255.255.255.255
ip pim sparse-mode
!
{% if __device.hostname in DEFN_NODE_ROLES['SPINE']  %}
{# SKIP SPINE #}
{% endif %}

{% if __device.hostname in DEFN_NODE_ROLES['BORDER'] %}
    interface {{DEFN_LOOP_NAME['IPSEC']}}
    description IPSEC TUNNEL SOURCE INTERFACE
    ip address {{DEFN_LOOP_IPSEC[__device.hostname]}} 255.255.255.255
    ip ospf {{FABRIC_UNDERLAY['instance_id']}} area {{FABRIC_UNDERLAY['area']}}
    !
    interface {{DEFN_LOOP_NAME['MCLUSTER']}}
    description NVE MULTICLUSTER INTERFACE
    ip address {{DEFN_LOOP_MCLUSTER[__device.hostname]}} 255.255.255.255
    !
{% else  %}
    {% for input_vrf in vrf_objs %}
        {% set ip = DEFN_LOOP_UNDERLAY[__device.hostname] %}
        {% set split_ip = ip.split('\\.') %}
        {% set last_octet = split_ip[3] %}
        interface Loopback{{input_vrf.id}}
        description OVERLAY-VRF-{{input_vrf.name}}
        vrf forwarding {{input_vrf.name}}
        ip address {{DEFN_LOOP_OVERLAY[input_vrf.name]}}{{last_octet}} 255.255.255.255
        ip pim sparse-mode
        !
    {% endfor %}
{% endif %}

